// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: '',
  });
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Validation helpers
  const isValidEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const validateStep = (step: number): boolean => {
    const newErrors: Record<string, string> = {};

    if (step === 1) {
      if (!formData.name.trim()) newErrors.name = 'Name is required';
      if (!formData.email.trim()) newErrors.email = 'Email is required';
      if (formData.email && !isValidEmail(formData.email)) newErrors.email = 'Invalid email format';
    } else if (step === 2) {
      if (formData.satisfaction === 0) newErrors.satisfaction = 'Please select a satisfaction rating';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const canProceedToNext = (): boolean => {
    return validateStep(currentStep);
  };

  const handleNext = (): void => {
    if (canProceedToNext()) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handleBack = (): void => {
    setCurrentStep(currentStep - 1);
  };

  const handleInputChange = (field: string, value: string): void => {
    setFormData(prev => ({ ...prev, [field]: value }));
    if (errors[field]) {
      setErrors(prev => {
        const newErrors = { ...prev };
        delete newErrors[field];
        return newErrors;
      });
    }
  };

  const handleCheckboxChange = (feature: string, checked: boolean): void => {
    setFormData(prev => ({
      ...prev,
      features: checked
        ? [...prev.features, feature]
        : prev.features.filter(f => f !== feature),
    }));
  };

  const handleSubmit = (): void => {
    submit(formData);
  };

const progressPercentage = (currentStep / 5) * 100;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Progress bar */}
        <Box>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
            Step {currentStep === 5 ? 'Final Review' : `${currentStep} of 5`}
          </Text>
          <Progress value={progressPercentage} max={100} size="md" />
        </Box>
        <Divider margin="var(--ggui-spacing-2)" />

        {/* Step 1: Name and Email */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Your Information</Heading>
              <Input
                label="Name"
                placeholder="Enter your full name"
                value={formData.name}
                onChange={(value) => handleInputChange('name', value)}
                error={errors.name}
                required
              />
              <Input
                label="Email"
                type="email"
                placeholder="your@email.com"
                value={formData.email}
                onChange={(value) => handleInputChange('email', value)}
                error={errors.email}
                required
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>How satisfied are you?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={formData.satisfaction.toString()}
                onChange={(value) => setFormData(prev => ({ ...prev, satisfaction: parseInt(value) }))}
                error={errors.satisfaction}
                options={props.satisfactionLabels.map((label, index) => ({
                  value: (index + 1).toString(),
                  label: label,
                }))}
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>What features interest you?</Heading>
              <Stack gap="var(--ggui-spacing-3)">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={formData.features.includes(feature)}
                    onChange={(checked) => handleCheckboxChange(feature, checked)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

         {/* Step 4: Comments */}
         {currentStep === 4 && (
           <Card padding="var(--ggui-spacing-6)" shadow="md">
             <Stack gap="var(--ggui-spacing-4)">
               <Heading level={2}>Additional Comments</Heading>
               <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                 Help us understand your feedback better. This field is optional.
               </Text>
               <TextArea
                 label="Comments"
                 placeholder="Tell us more (optional)"
                 value={formData.comments}
                 onChange={(value) => setFormData(prev => ({ ...prev, comments: value }))}
                 maxLength={500}
                 showCount
                 rows={6}
               />
             </Stack>
           </Card>
         )}

        {/* Step 5: Final Review */}
        {currentStep === 5 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Review Your Answers</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Please review all your information before submitting.
              </Text>
              <Divider margin="var(--ggui-spacing-2)" />
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
                <Text variant="body">{formData.name}</Text>
              </Box>
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                <Text variant="body">{formData.email}</Text>
              </Box>
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Satisfaction Rating</Text>
                <Text variant="body">{props.satisfactionLabels[formData.satisfaction - 1]}</Text>
              </Box>
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Features of Interest</Text>
                <Stack gap="var(--ggui-spacing-1)">
                  {formData.features.length > 0 ? (
                    formData.features.map((feature) => (
                      <Text key={feature} variant="body">• {feature}</Text>
                    ))
                  ) : (
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">None selected</Text>
                  )}
                </Stack>
              </Box>
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Additional Comments</Text>
                <Text variant="body">{formData.comments || '(None provided)'}</Text>
              </Box>
            </Stack>
          </Card>
        )}

        <Divider margin="var(--ggui-spacing-2)" />
        {/* Navigation buttons */}
        <Row gap="var(--ggui-spacing-4)" justify="between">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          <Button
            variant="primary"
            onClick={currentStep === 5 ? handleSubmit : handleNext}
            disabled={currentStep > 1 && currentStep < 5 && !canProceedToNext()}
          >
            {currentStep === 5 ? 'Submit' : 'Next'}
          </Button>
        </Row>
      </Stack>
    </Container>
  );
}

