// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column?: string; title?: string; assignee?: string; dueDate?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Helper component for individual task card
function TaskCard({ task, onMove, onEdit }: { task: Props['tasks'][0]; onMove: (column: string) => void; onEdit: () => void }) {
  const getPriorityColor = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'var(--ggui-color-error-600)';
      case 'medium':
        return 'var(--ggui-color-warning-600)';
      case 'low':
        return 'var(--ggui-color-success-600)';
      default:
        return 'var(--ggui-color-primary-600)';
    }
  };

  const getPriorityVariant = (priority?: string): 'error' | 'warning' | 'success' | 'default' => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
        return 'success';
      default:
        return 'default';
    }
  };

  const formatDueDate = (date?: string) => {
    if (!date) return null;
    const d = new Date(date);
    return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
  };

  return (
    <Card padding="var(--ggui-spacing-3)" shadow="sm" border={true}>
      <Stack gap="var(--ggui-spacing-2)">
        <Row justify="between" align="center">
          <Text variant="body" weight="medium" style={{ flex: 1 }}>{task.title || 'Untitled'}</Text>
          <Button variant="ghost" size="xs" onClick={onEdit}>Edit</Button>
        </Row>
        <Row gap="var(--ggui-spacing-2)" align="center" wrap={true}>
          {task.priority && <Badge variant={getPriorityVariant(task.priority)} size="sm">{task.priority}</Badge>}
          {task.assignee && <Avatar name={task.assignee} size="sm" shape="circle" />}
          {task.dueDate && <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{formatDueDate(task.dueDate)}</Text>}
        </Row>
      </Stack>
    </Card>
  );
}


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // Local state
  const [tasks, setTasks] = useState(props.tasks || []);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [editingAssignee, setEditingAssignee] = useState('');
  const [editingDueDate, setEditingDueDate] = useState('');
  const [addingColumn, setAddingColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskAssignee, setNewTaskAssignee] = useState('');
  const [newTaskDueDate, setNewTaskDueDate] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  // Sync props tasks to local state
  useEffect(() => {
    setTasks(props.tasks || []);
  }, [props.tasks]);

  // Handle real-time updates from other users
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'create' && task) {
        setTasks((prev) => [...prev, { ...task, id: task.id || `task-${Date.now()}` }]);
      } else if (action === 'move' && task) {
        setTasks((prev) => prev.map((t) => (t.id === task.id ? { ...t, column: task.column } : t)));
      } else if (action === 'edit' && task) {
        setTasks((prev) => prev.map((t) => (t.id === task.id ? { ...t, ...task } : t)));
      } else if (action === 'delete' && task) {
        setTasks((prev) => prev.filter((t) => t.id !== task.id));
      }
    }
  }, [taskChanged.latest]);

  // Compute totals
  const totalTasks = tasks.length;
  const completedCount = tasks.filter((t) => t.column === 'done').length;

  // Handle task move
  const handleMoveTask = useCallback((taskId: string, targetColumn: string) => {
    taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
    setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, column: targetColumn } : t)));
  }, [taskUpdate]);

  // Handle task edit start
  const handleEditTask = useCallback((taskId: string) => {
    const task = tasks.find((t) => t.id === taskId);
    if (task) {
      setEditingTaskId(taskId);
      setEditingTitle(task.title || '');
      setEditingAssignee(task.assignee || '');
      setEditingDueDate(task.dueDate || '');
    }
  }, [tasks]);

  // Handle task edit save
  const handleSaveEdit = useCallback((taskId: string) => {
    taskUpdate({
      action: 'edit',
      taskId,
      data: {
        column: tasks.find((t) => t.id === taskId)?.column || 'todo',
        title: editingTitle,
        assignee: editingAssignee,
        dueDate: editingDueDate,
      }
    });
    setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, title: editingTitle, assignee: editingAssignee, dueDate: editingDueDate } : t)));
    setEditingTaskId(null);
    setEditingTitle('');
    setEditingAssignee('');
    setEditingDueDate('');
  }, [editingTitle, editingAssignee, editingDueDate, taskUpdate, tasks]);

  // Handle add task
  const handleAddTask = useCallback((columnId: string) => {
    const newTaskId = `task-${Date.now()}`;
    const newTask = {
      id: newTaskId,
      title: newTaskTitle || 'New Task',
      priority: newTaskPriority,
      column: columnId,
      assignee: newTaskAssignee,
      dueDate: newTaskDueDate,
    };
    taskUpdate({
      action: 'create',
      taskId: newTaskId,
      data: {
        column: columnId,
        title: newTask.title,
        assignee: newTaskAssignee,
        dueDate: newTaskDueDate,
      }
    });
    setTasks((prev) => [...prev, newTask]);
    setNewTaskTitle('');
    setNewTaskAssignee('');
    setNewTaskDueDate('');
    setNewTaskPriority('medium');
    setAddingColumn(null);
  }, [newTaskTitle, newTaskAssignee, newTaskDueDate, newTaskPriority, taskUpdate]);

  // Get tasks for a column
  const getTasksForColumn = useCallback((columnId?: string) => {
    return tasks.filter((t) => t.column === columnId);
  }, [tasks]);

  // Priority options for Select
  const priorityOptions = [
    { value: 'low', label: 'Low' },
    { value: 'medium', label: 'Medium' },
    { value: 'high', label: 'High' },
  ];

return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)" as="main">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary bar */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Row justify="between" align="center">
            <Text variant="body">
              <strong>{totalTasks}</strong> total tasks — <strong>{completedCount}</strong> completed
            </Text>
            <Badge variant="primary" size="md">{Math.round((completedCount / Math.max(1, totalTasks)) * 100)}% Complete</Badge>
          </Row>
        </Card>

        {/* Kanban board */}
         <Row gap="var(--ggui-spacing-4)" align="start" wrap={false} style={{ overflowX: 'auto' }}>
          {props.columns && props.columns.map((column) => {
            const columnTasks = getTasksForColumn(column.id);
            const isAdding = addingColumn === column.id;

            return (
              <Card
                key={column.id}
                padding="var(--ggui-spacing-4)"
                shadow="sm"
                 style={{ minWidth: 'var(--ggui-spacing-12)', maxWidth: 'var(--ggui-spacing-12)', flex: '0 0 auto' }}
              >
                 <Stack gap="var(--ggui-spacing-3)">
                  {/* Column header */}
                  <Box>
                    <Row justify="between" align="center">
                      <Heading level={4}>{column.name}</Heading>
                      <Badge variant="secondary" size="sm">{columnTasks.length}</Badge>
                    </Row>
                  </Box>
                  <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" color="var(--ggui-color-outline)" />

                  {/* Task list */}
                   <Stack gap="var(--ggui-spacing-2)" style={{ flex: 1, minHeight: 'var(--ggui-spacing-12)' }}>
                    {columnTasks.length > 0 ? (
                      columnTasks.map((task) =>
                        editingTaskId === task.id ? (
                            <Card
                              key={task.id}
                              padding="var(--ggui-spacing-3)"
                              shadow="sm"
                              border={true}
                              style={{ background: 'var(--ggui-color-primary-50)' }}
                            >
                              <Stack gap="var(--ggui-spacing-2)">
                                <Input
                                  label="Task title"
                                  value={editingTitle}
                                  onChange={setEditingTitle}
                                  placeholder="Enter task title"
                                />
                                <Input
                                  label="Assignee"
                                  value={editingAssignee}
                                  onChange={setEditingAssignee}
                                  placeholder="Enter assignee initials"
                                />
                                <Input
                                  label="Due date"
                                  type="text"
                                  value={editingDueDate}
                                  onChange={setEditingDueDate}
                                  placeholder="YYYY-MM-DD"
                                />
                                <Row gap="var(--ggui-spacing-2)" justify="end">
                                  <Button
                                    variant="ghost"
                                    size="sm"
                                    aria-label="Cancel task edit"
                                    onClick={() => {
                                      setEditingTaskId(null);
                                      setEditingTitle('');
                                      setEditingAssignee('');
                                      setEditingDueDate('');
                                    }}
                                  >
                                    Cancel
                                  </Button>
                                  <Button
                                    variant="primary"
                                    size="sm"
                                    aria-label="Save task edit"
                                    onClick={() => handleSaveEdit(task.id!)}
                                  >
                                    Save
                                  </Button>
                                </Row>
                              </Stack>
                            </Card>
                         ) : (
                            <Box
                              key={task.id}
                              as={Hoverable}
                              tabIndex={0}
                              onKeyDown={(e) => {
                                if (e.key === 'Enter' || e.key === ' ') {
                                  e.preventDefault();
                                  handleEditTask(task.id!);
                                }
                              }}
                              style={{ outline: 'none', borderRadius: 'var(--ggui-shape-radius-lg)' }}
                              hoverStyle={{ opacity: 0.8, background: 'var(--ggui-color-surfaceVariant)' }}
                            >
                              <Card
                                padding="var(--ggui-spacing-3)"
                                shadow="sm"
                                border={true}
                                style={{ cursor: 'pointer' }}
                              >
                                <Stack gap="var(--ggui-spacing-2)">
                                  <Row justify="between" align="start">
                                    <Text variant="body" weight="medium" style={{ flex: 1, cursor: 'pointer' }}>
                                      {task.title || 'Untitled'}
                                    </Text>
                                     <Dropdown
                                       trigger={<Button variant="ghost" size="xs" aria-label={`Move task: ${task.title} to another column`}>Move</Button>}
                                       options={props.columns
                                         ?.filter((c) => c.id !== column.id)
                                         .map((c) => ({
                                           value: c.id!,
                                           label: c.name || '',
                                         })) || []}
                                       value=""
                                       onChange={(targetColumn) => handleMoveTask(task.id!, targetColumn)}
                                     />
                                  </Row>
                                  <Row gap="var(--ggui-spacing-2)" align="center" wrap={true}>
                                    {task.priority && (
                                      <Badge
                                        variant={
                                          task.priority === 'high'
                                            ? 'error'
                                            : task.priority === 'medium'
                                            ? 'warning'
                                            : 'success'
                                        }
                                        size="sm"
                                      >
                                        {task.priority}
                                      </Badge>
                                    )}
                                    {task.assignee && <Avatar name={task.assignee} size="sm" shape="circle" aria-label={`Assigned to ${task.assignee}`} />}
                                    {task.dueDate && (
                                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" aria-label={`Due: ${new Date(task.dueDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`}>
                                        {new Date(task.dueDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                                      </Text>
                                    )}
                                  </Row>
                                  <Row gap="var(--ggui-spacing-2)" justify="end">
                                    <Button variant="ghost" size="xs" aria-label={`Edit task: ${task.title}`} onClick={() => handleEditTask(task.id!)}>
                                      Edit
                                    </Button>
                                  </Row>
                                </Stack>
                              </Card>
                            </Box>
                         )
                       )
                     ) : (
                      <Box style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: 'var(--ggui-spacing-12)', padding: 'var(--ggui-spacing-4)' }}>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" align="center">
                          No tasks yet
                        </Text>
                      </Box>
                     )}
