// Helper hook for animation retriggering
function useAnimationKey(dep: any): any {
  const [key, setKey] = React.useState(0);
  const prevDep = useRef(dep);

  useEffect(() => {
    if (prevDep.current !== dep) {
      setKey((k) => k + 1);
      prevDep.current = dep;
    }
  }, [dep]);

  return key;
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State: maintain merged stock data
  const [stocks, setStocks] = useState<any[]>(props.stocks || []);
  const [lastUpdatedTime, setLastUpdatedTime] = useState<Date | null>(null);
  const [updatingSymbols, setUpdatingSymbols] = useState<Set<string>>(new Set());

  // Effect: merge initial props into state
  useEffect(() => {
    if (props.stocks && props.stocks.length > 0) {
      setStocks(props.stocks);
    }
  }, [props.stocks]);

  // Effect: merge stream updates into stock data
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      setStocks((prevStocks) => {
        const updated = prevStocks.map((stock) => {
          if (stock.symbol === update.symbol) {
            return {
              ...stock,
              price: update.price !== undefined ? update.price : stock.price,
              change: update.change !== undefined ? update.change : stock.change,
              changePercent: update.changePercent !== undefined ? update.changePercent : stock.changePercent,
            };
          }
          return stock;
        });
        return updated;
      });

      // Update timestamp and highlight this stock
      setLastUpdatedTime(new Date());
      if (update.symbol) {
        setUpdatingSymbols((prev) => new Set(prev).add(update.symbol));
        setTimeout(() => {
          setUpdatingSymbols((prev) => {
            const next = new Set(prev);
            next.delete(update.symbol!);
            return next;
          });
        }, 1000); // Remove highlight after 1 second
      }
    }
  }, [priceUpdate.latest]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-8)">
        {/* Header with title and last updated timestamp */}
        <Stack gap="var(--ggui-spacing-2)" align="start">
          <Heading level={1} color="var(--ggui-color-onSurface)">
            Market Watch
          </Heading>
          <Row align="center" gap="var(--ggui-spacing-2)">
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Last Updated:
            </Text>
            <Text
              variant="bodySmall"
              weight="semibold"
              color="var(--ggui-color-primary-600)"
            >
              {lastUpdatedTime
                ? lastUpdatedTime.toLocaleTimeString()
                : 'Waiting for updates...'}
            </Text>
          </Row>
        </Stack>

        {/* Divider separating header from market status */}
        <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

        {/* Market status indicator */}
        {marketStatus.latest && (
          <Box
            padding="var(--ggui-spacing-3)"
            background="var(--ggui-color-primary-50)"
            borderRadius="var(--ggui-shape-radius-md)"
            role="region"
            aria-label="Market status indicator"
          >
            <Row align="center" gap="var(--ggui-spacing-2)">
              <Badge variant="primary" size="sm">
                {marketStatus.latest.status || 'unknown'}
              </Badge>
              <Text variant="bodySmall" color="var(--ggui-color-primary-700)">
                Market Status: {marketStatus.latest.status}
              </Text>
            </Row>
          </Box>
        )}

        {/* Responsive grid of stock cards */}
        {stocks && stocks.length > 0 ? (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap="var(--ggui-spacing-4)">
            {stocks.map((stock) => (
              <StockCard
                key={stock.symbol || Math.random()}
                stock={stock}
                isUpdating={updatingSymbols.has(stock.symbol || '')}
              />
            ))}
          </CardGrid>
        ) : (
          <Box
            padding="var(--ggui-spacing-8)"
            background="var(--ggui-color-surfaceVariant)"
            borderRadius="var(--ggui-shape-radius-lg)"
          >
            <Stack align="center" justify="center" gap="var(--ggui-spacing-3)">
              <Icon name="trending-down" size={32} color="var(--ggui-color-onSurfaceVariant)" aria-label="No stocks to display" />
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" align="center">
                No stocks to display
              </Text>
            </Stack>
          </Box>
        )}
      </Stack>
    </Container>
  );
